journal_teachers_html_template_style:
html {
	background-color: #f0f0f0;
}
html body {
  margin: 20px auto;
  max-width: calc(100vw - 82px);
	min-height: calc(100vh - 82px);
  padding: 20px;
  border: 1px solid black;
  background-color: white;
}
html header img {
	width: auto;
	height: 110px;
}
html header img[alt=\"logo-stowarzyszenie\"] {
	height: 130px;
}
main table {
	margin: 20pt auto;
	max-width: 100%;
	border-collapse: collapse;
}
main table tr {
	border-bottom: 1pt solid black;
}
main table tr:first-child {
	border-top: 1pt solid black;
}
main table th,
main table td {
	padding: 2pt;
	border-left: 1pt dotted black;
}
main table th:first-child,
main table td:first-child {
	border-left: none;
}
main table th[data-key=\"id\"],
main table td[data-key=\"id\"]{
	text-align: center;
	font-weight: bold;
}
main table td[data-key=\"student\"]{
	font-weight: bold;
}
main table th[data-key=\"student duration detailed\"],
main table td[data-key=\"student duration detailed\"],
main table th[data-key=\"teacher duration detailed\"],
main table td[data-key=\"teacher duration detailed\"],
main table th[data-key=\"type duration detailed\"],
main table td[data-key=\"type duration detailed\"],
main table th[data-key=\"type duration simple\"],
main table td[data-key=\"type duration simple\"]
{
	font-size: 0.6em;
  vertical-align: bottom;
  text-align: center;
}

main table th[data-key=\"student duration detailed\"] span,
main table td[data-key=\"student duration detailed\"] span,
main table th[data-key=\"teacher duration detailed\"] span,
main table td[data-key=\"teacher duration detailed\"] span,
main table th[data-key=\"type duration detailed\"] span,
main table td[data-key=\"type duration detailed\"] span,
main table th[data-key=\"type duration simple\"] span,
main table td[data-key=\"type duration simple\"] span
{
  -ms-writing-mode: tb-rl;
  -webkit-writing-mode: vertical-rl;
  writing-mode: vertical-rl;
  transform: rotate(0deg);
/*  white-space: nowrap;*/
}
main table td {
	font-size: 0.7em;
}
main table th[data-key=\"signature\"],
main table td[data-key=\"signature\"]{
	width: 50pt;
}
footer {
	margin-top: 20py;
	font-size: 0.8em;
}

@media print {
	* {
		color: #000 !important;    
		background-color: #fff !important;
	}
	body {
		border: none !important;
		max-width: inherit !important;
		min-width: inherit !important;
		margin: 0 !important;
		padding: 0 !important;
	}
}

